import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface BookData {
  title: string;
  author: string;
  synopsis: string;
  style: string;
}

export interface GeneratedText {
  clickbait: string;
  short_caption: string;
  long_caption: string;
}

export interface GeneratedContent {
  covers: string[]; // Array of base64 strings
  text: GeneratedText;
}

export const BOOK_STYLES = [
  { id: 'cinematic', label: 'Cinematic Movie Poster', desc: 'Dramatic lighting, realistic textures' },
  { id: 'minimalist', label: 'Minimalist Vector', desc: 'Clean lines, bold colors, symbolic' },
  { id: 'fantasy', label: 'Epic Fantasy', desc: 'Magical atmosphere, digital painting style' },
  { id: 'romance', label: 'Soft Romance', desc: 'Pastel tones, dreamy, emotional' },
  { id: 'thriller', label: 'Dark Thriller', desc: 'High contrast, shadows, mysterious' },
  { id: 'cyberpunk', label: 'Cyberpunk / Sci-Fi', desc: 'Neon lights, futuristic elements' },
  { id: 'watercolor', label: 'Artistic Watercolor', desc: 'Fluid, organic, hand-painted look' },
  { id: 'horror', label: 'Gothic Horror', desc: 'Gritty, dark, terrifying atmosphere' },
  { id: 'anime', label: 'Anime / Manga', desc: 'Japanese animation style, expressive' },
  { id: 'vintage', label: 'Vintage Retro', desc: 'Old paper texture, classic typography style' },
];

import { GoogleGenAI, Type, SchemaType } from "@google/genai";
import { BookData, GeneratedText } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const generateMarketingText = async (data: BookData): Promise<GeneratedText> => {
  if (!apiKey) throw new Error("API Key is missing");

  const prompt = `
    Create a marketing package for a fiction story.
    Title: ${data.title}
    Author: ${data.author}
    Synopsis: ${data.synopsis}

    Tasks:
    1. Create a "clickbait" title that is catchy and intriguing.
    2. Write a "short_caption" (approx 100 words). It MUST start with a strong Hook and end with a Cliffhanger that serves as a Call to Action (CTA).
    3. Write a "long_caption" (approx 500 words). It MUST be engaging, immersive, start with a powerful Hook, and end with a suspenseful Cliffhanger CTA.

    Language: Indonesian (Bahasa Indonesia).
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          clickbait: { type: Type.STRING },
          short_caption: { type: Type.STRING },
          long_caption: { type: Type.STRING },
        },
        required: ['clickbait', 'short_caption', 'long_caption'],
      },
    },
  });

  const text = response.text;
  if (!text) throw new Error("Failed to generate text");

  return JSON.parse(text) as GeneratedText;
};

export const generateSingleCover = async (data: BookData, seedOffset: number): Promise<string> => {
  if (!apiKey) throw new Error("API Key is missing");

  // Providing variation by slightly tweaking the prompt based on seed/index
  const variations = [
    "Close-up composition",
    "Wide angle scene",
    "Character focused",
    "Symbolic and atmospheric"
  ];

  const variation = variations[seedOffset % variations.length];

  const prompt = `
    Create a stunning, high-quality book cover art.
    Title context: ${data.title}
    Genre/Style: ${data.style}
    Synopsis context: ${data.synopsis}

    Key Visual Requirements:
    1. Aspect Ratio: Vertical Portrait (compatible with 2:3).
    2. Faces/Characters: Must depict people of Asian or Indonesian descent.
    3. Composition: ${variation}.
    4. Quality: 4k resolution, highly detailed, trending on artstation.
    5. Do NOT include text on the image if possible, focus on the illustration.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image', // Using flash-image for speed and efficiency for demo
    contents: {
        parts: [{ text: prompt }]
    },
    config: {
        imageConfig: {
            aspectRatio: "3:4", // Closest API supported ratio to 2:3
        }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error("No image generated");
};

export const generateBookAssets = async (data: BookData): Promise<{ text: GeneratedText; covers: string[] }> => {

  // 1. Generate Text
  const textPromise = generateMarketingText(data);

  // 2. Generate 4 Covers in parallel
  // We call the API 4 times to get 4 distinct variations
  const coverPromises = [0, 1, 2, 3].map(i => generateSingleCover(data, i));

  try {
    const [text, ...covers] = await Promise.all([textPromise, ...coverPromises]);
    return { text, covers };
  } catch (error) {
    console.error("Error generating assets:", error);
    throw error;
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading = false, 
  className = '', 
  disabled,
  ...props 
}) => {
  const baseStyles = "px-6 py-3 rounded-xl font-semibold transition-all duration-200 flex items-center justify-center gap-2";

  const variants = {
    primary: "bg-blue-600 hover:bg-blue-700 text-white shadow-lg shadow-blue-200",
    secondary: "bg-slate-800 hover:bg-slate-900 text-white shadow-lg",
    outline: "border-2 border-blue-200 hover:border-blue-600 text-blue-800 hover:bg-blue-50"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${disabled || isLoading ? 'opacity-50 cursor-not-allowed' : ''} ${className}`}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading && (
        <svg className="animate-spin -ml-1 mr-2 h-5 w-5" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
        </svg>
      )}
      {children}
    </button>
  );
};

