                   <div className="h-2 bg-slate-100 rounded-full overflow-hidden">
                     <div className="h-full bg-blue-600 animate-pulse w-2/3 rounded-full"></div>
                   </div>
                 </div>
               </div>
            )}

            {results && !loading && (
              <ResultSection results={results} />
            )}
          </div>

        </div>
      </main>
    </div>
  );
};

export default App;

